mapper.select:
SELECT
e.*,
p.provider_name
FROM llm_endpoint e
LEFT JOIN llm_provider p ON e.provider_id = p.id
WHERE 1=1

    AND e.tenant_id = #{bo.tenantId}


    AND e.endpoint_code = #{bo.endpointCode}


    AND e.endpoint_name LIKE CONCAT('%', #{bo.endpointName}, '%')


    AND e.provider_id = #{bo.providerId}


    AND p.provider_name LIKE CONCAT('%', #{bo.providerName}, '%')


    AND e.base_url = #{bo.baseUrl}


    AND e.api_key = #{bo.apiKey}


    AND e.default_model_id = #{bo.defaultModelId}


    AND e.status = #{bo.status}


    AND e.priority = #{bo.priority}


    AND e.tags_json = #{bo.tagsJson}


    AND e.chat_completions_path = #{bo.chatCompletionsPath}


    AND e.embeddings_path = #{bo.embeddingsPath}


    AND e.auth_header_name = #{bo.authHeaderName}


    AND e.auth_header_prefix = #{bo.authHeaderPrefix}


    AND e.extra_headers_json = #{bo.extraHeadersJson}


    AND e.extra_params_json = #{bo.extraParamsJson}
